PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>
SELECT DISTINCT ?winner WHERE {
  ?awardCategory wdt:P1297 wd:Q108084271 .
  ?winner wdt:P166 ?awardCategory .
  ?winner wdt:P19 ?birthplace .
  ?birthplace wdt:P131 ?state .
  ?state wdt:P17 wd:Q30 .
  VALUES ?state {
    wd:Q36 wd:Q105 wd:Q44
  }
}

